from trace_utils import build_tool_trace


def test_trace_payload_shape():
    payload = build_tool_trace('write', {'path': 'a.py'}, 'ok')
    assert payload['tool_name'] == 'write'
    assert payload['input']['arguments'] == {'path': 'a.py'}
    assert payload['output']['content'] == 'ok'

